#!/usr/bin/env python3
"""apply_crucible_art.py — inject Crucible portraits into assets/assets.json.
Values are RAW base64 (Crucible placeholders already carry the data: prefix in source).
Includes hi-res Tituba (a27) and the two new cards Rebecca (a986) & Town of Salem (a987).
Idempotent; run from repo root."""
import json, os, sys
root=os.path.dirname(os.path.abspath(__file__))
ap=os.path.join(root,"assets/assets.json")
if not os.path.exists(ap): sys.exit("[apply] assets/assets.json not found — run from repo root")
assets=json.load(open(ap)); ART={
  "a14": "",  # hale
  "a21": "",  # abigail
  "a22": "",  # jproctor
  "a23": "",  # eproctor
  "a24": "",  # parris
  "a25": "",  # putnam
  "a26": "",  # giles
  "a27": "",  # tituba (HI-RES)
  "a128": "",  # mary
  "a129": "",  # danforth
  "a986": "",  # rebecca (NEW)
  "a987": "",  # town of salem (NEW)
}
for k,v in ART.items(): assets[k]=v
json.dump(assets, open(ap,"w"))
print(f"[apply] wrote {len(ART)} Crucible portraits (raw base64) into assets.json")
